import * as React from 'react';
import Box from '@mui/material/Box';
import AppBar from '@mui/material/AppBar';
import Toolbar from '@mui/material/Toolbar';
import Typography from '@mui/material/Typography';
import { useLocation } from 'react-router-dom';


const FooterDesign = () => {
  return (
    // <Box position="fixed" left={0} bottom={0} right={0} alignItems={'center'} height={56} sx={{backgroundColor: 'yellow'}}>
    //   <Typography component="p" sx={{ fontSize: '16px', marginBottom: '0px', fontWeight: '300', color: '#32292F', background: 'white' }}>
    //     2024 (c) Daria Schumm
    //   </Typography>
    // </Box>

    // <Box sx={{ flexGrow: 1 }}>
			<AppBar position="fixed" color='inherit' sx={{ boxShadow: '0px 0px 0px #e3e3e3', top: 'auto', bottom: 0, alignItems: 'center' }}>
				<Toolbar sx={{ minHeight: '56px!important' }}>
          2024 (c) Daria Schumm
				</Toolbar>
			</AppBar>
		// </Box>
  )
}


function Footer () {
  const { pathname } = useLocation();
  return (
    pathname !== '/' && pathname !== '/collections' ?
    <FooterDesign /> :
    null
  )
}

export default Footer;
